{
  "name": "TokenCraft: Custom Tokenizer Builder",
  "description": "An interactive tool to build, test, and visualize custom text tokenizers. Use manual Regex rules or ask AI to design one for you."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
