export interface Token {
  id: number;
  value: string;
  type?: string;
  index: number; // Position in original string
}

export interface TokenizerConfig {
  name: string;
  regex: string;
  flags: string;
  description?: string;
}

export interface TokenStats {
  totalTokens: number;
  uniqueTokens: number;
  averageLength: number;
  characterCount: number;
}

import { TokenizerConfig } from './types';

export const PRESET_TOKENIZERS: TokenizerConfig[] = [
  {
    name: 'Whitespace',
    regex: '\\S+',
    flags: 'g',
    description: 'Splits text by whitespace characters. Matches any non-whitespace sequence.',
  },
  {
    name: 'Word & Punctuation',
    regex: '\\w+|[^\\w\\s]+',
    flags: 'g',
    description: 'Matches words (alphanumeric) and sequences of punctuation separately.',
  },
  {
    name: 'Simple Word',
    regex: '[a-zA-Z]+',
    flags: 'g',
    description: 'Extracts only alphabetic words, ignoring numbers and punctuation.',
  },
  {
    name: 'Twitter / Social',
    regex: '[#@]?[\\w]+|[^\\w\\s]+',
    flags: 'g',
    description: 'Keeps hashtags (#tag) and mentions (@user) together as single tokens.',
  },
  {
    name: 'Code (Simple)',
    regex: '\\w+|==|!=|<=|>=|&&|\\|\\||\\p{P}',
    flags: 'gu',
    description: 'Attempts to keep code operators together while splitting keywords.',
  },
];

export const DEFAULT_TEXT = `Hello, Tokenizer!
This is a sample text to test your "custom" build.
Try adding an email like test@example.com or a #hashtag to see how it splits.`;

import { GoogleGenAI, Type } from "@google/genai";
import { TokenizerConfig } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateTokenizerWithGemini = async (
  prompt: string
): Promise<TokenizerConfig | null> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Create a JavaScript Regular Expression (Regex) that functions as a tokenizer based on this user description: "${prompt}".

      The regex should match the *tokens* themselves, not the delimiters. 
      For example, if the user wants to split by space, the regex should match non-space characters (\\S+).
      If the user wants to keep emails together, the regex should explicitly match email patterns OR other words.

      Return the result as a JSON object.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            regex: {
              type: Type.STRING,
              description: "The JavaScript regex pattern string (without slashes). Escape backslashes correctly.",
            },
            flags: {
              type: Type.STRING,
              description: "Regex flags (e.g., 'g', 'gi'). Usually 'g' is required.",
            },
            description: {
              type: Type.STRING,
              description: "A short explanation of how this regex works.",
            },
            name: {
              type: Type.STRING,
              description: "A short, creative name for this tokenizer strategy.",
            },
          },
          required: ["regex", "flags", "description", "name"],
        },
      },
    });

    if (response.text) {
      return JSON.parse(response.text) as TokenizerConfig;
    }
    return null;
  } catch (error) {
    console.error("Error generating tokenizer:", error);
    throw error;
  }
};

export const explainTokenizer = async (regex: string): Promise<string> => {
    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: `Explain what this Regular Expression does in the context of text tokenization in one simple sentence: /${regex}/`,
        });
        return response.text || "No explanation available.";
    } catch (e) {
        return "Could not generate explanation.";
    }
}

import React, { useState } from 'react';
import { Settings, Wand2, RefreshCw, AlertCircle } from 'lucide-react';
import { PRESET_TOKENIZERS } from '../constants';
import { TokenizerConfig } from '../types';
import { generateTokenizerWithGemini } from '../services/geminiService';

interface TokenizerBuilderProps {
  config: TokenizerConfig;
  onConfigChange: (config: TokenizerConfig) => void;
}

const TokenizerBuilder: React.FC<TokenizerBuilderProps> = ({ config, onConfigChange }) => {
  const [prompt, setPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handlePresetChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const selected = PRESET_TOKENIZERS.find((p) => p.name === e.target.value);
    if (selected) {
      onConfigChange(selected);
      setError(null);
    }
  };

  const handleRegexChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    onConfigChange({ ...config, regex: e.target.value, name: 'Custom' });
    setError(null);
  };

  const handleFlagsChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    onConfigChange({ ...config, flags: e.target.value, name: 'Custom' });
  };

  const handleAiGenerate = async () => {
    if (!prompt.trim()) return;
    setIsGenerating(true);
    setError(null);
    try {
      const newConfig = await generateTokenizerWithGemini(prompt);
      if (newConfig) {
        onConfigChange(newConfig);
      } else {
        setError("AI could not generate a valid config.");
      }
    } catch (err) {
      setError("Failed to generate tokenizer. Please try again.");
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 flex flex-col gap-6 h-full">
      <div className="flex items-center gap-2 border-b border-slate-100 pb-4">
        <Settings className="w-5 h-5 text-indigo-600" />
        <h2 className="text-lg font-semibold text-slate-800">Configuration</h2>
      </div>

      {/* AI Builder Section */}
      <div className="bg-indigo-50 p-4 rounded-lg border border-indigo-100">
        <label className="block text-sm font-medium text-indigo-900 mb-2 flex items-center gap-2">
          <Wand2 className="w-4 h-4" />
          AI Magic Builder
        </label>
        <p className="text-xs text-indigo-700 mb-3">
          Describe how you want to tokenize text (e.g., "Split by whitespace but keep emails and URLs").
        </p>
        <div className="flex gap-2">
          <input
            type="text"
            value={prompt}
            onChange={(e) => setPrompt(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleAiGenerate()}
            placeholder="Describe your tokenizer..."
            className="flex-1 px-3 py-2 text-sm border border-indigo-200 rounded-md focus:outline-none focus:ring-2 focus:ring-indigo-500 bg-white"
          />
          <button
            onClick={handleAiGenerate}
            disabled={isGenerating || !prompt.trim()}
            className="px-4 py-2 bg-indigo-600 text-white text-sm font-medium rounded-md hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2 transition-colors"
          >
            {isGenerating ? <RefreshCw className="w-4 h-4 animate-spin" /> : 'Generate'}
          </button>
        </div>
        {error && (
            <div className="mt-2 flex items-center gap-1 text-xs text-red-600">
                <AlertCircle className="w-3 h-3" />
                {error}
            </div>
        )}
      </div>

      <hr className="border-slate-100" />

      {/* Manual Configuration */}
      <div className="flex flex-col gap-4">
        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">Preset Strategies</label>
          <select
            value={PRESET_TOKENIZERS.some(p => p.name === config.name) ? config.name : "Custom"}
            onChange={handlePresetChange}
            className="w-full px-3 py-2 text-sm border border-slate-300 rounded-md focus:outline-none focus:ring-2 focus:ring-indigo-500 bg-slate-50"
          >
            <option value="Custom">Custom / AI Generated</option>
            {PRESET_TOKENIZERS.map((p) => (
              <option key={p.name} value={p.name}>
                {p.name}
              </option>
            ))}
          </select>
        </div>

        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">Regex Pattern</label>
          <div className="font-mono text-sm flex items-center border border-slate-300 rounded-md overflow-hidden focus-within:ring-2 focus-within:ring-indigo-500">
            <span className="bg-slate-100 px-3 py-2 text-slate-500 border-r border-slate-300">/</span>
            <input
              type="text"
              value={config.regex}
              onChange={handleRegexChange}
              className="flex-1 px-3 py-2 outline-none text-slate-800"
              placeholder="\w+"
            />
            <span className="bg-slate-100 px-3 py-2 text-slate-500 border-l border-slate-300">/</span>
            <input
              type="text"
              value={config.flags}
              onChange={handleFlagsChange}
              className="w-16 px-2 py-2 outline-none text-slate-800 bg-slate-50 text-center"
              placeholder="flags"
            />
          </div>
          <p className="text-xs text-slate-500 mt-1">
             JavaScript Regex syntax. Use groups <code>( )</code> carefully.
          </p>
        </div>

        {config.description && (
          <div className="text-xs text-slate-600 italic bg-slate-50 p-3 rounded border border-slate-200">
            "{config.description}"
          </div>
        )}
      </div>
    </div>
  );
};

export default TokenizerBuilder;

