import React, { useState, useEffect, useCallback } from 'react';
import { Terminal, Code2, Share2, HelpCircle } from 'lucide-react';
import TokenizerBuilder from './components/TokenizerBuilder';
import TokenDisplay from './components/TokenDisplay';
import { TokenizerConfig, Token, TokenStats } from './types';
import { PRESET_TOKENIZERS, DEFAULT_TEXT } from './constants';

const App: React.FC = () => {
  const [inputText, setInputText] = useState(DEFAULT_TEXT);
  const [config, setConfig] = useState<TokenizerConfig>(PRESET_TOKENIZERS[0]);
  const [tokens, setTokens] = useState<Token[]>([]);
  const [stats, setStats] = useState<TokenStats>({
    totalTokens: 0,
    uniqueTokens: 0,
    averageLength: 0,
    characterCount: 0,
  });
  const [regexError, setRegexError] = useState<string | null>(null);

  const processText = useCallback(() => {
    try {
      const regex = new RegExp(config.regex, config.flags);
      const matches: RegExpMatchArray[] = Array.from(inputText.matchAll(regex));

      let idCounter = 0;
      const vocabMap = new Map<string, number>();

      const newTokens: Token[] = matches.map((match) => {
        const value = match[0];

        // Simple ID assignment for unique tokens (Vocabulary ID)
        if (!vocabMap.has(value)) {
            vocabMap.set(value, idCounter++);
        }

        return {
          id: vocabMap.get(value)!, // Token ID (Vocab ID)
          value: value,
          index: match.index !== undefined ? match.index : -1,
        };
      });

      setTokens(newTokens);
      setRegexError(null);

      // Calculate Stats
      const uniqueCount = new Set(newTokens.map(t => t.value)).size;
      const totalLen = newTokens.reduce((acc, t) => acc + t.value.length, 0);

      setStats({
        totalTokens: newTokens.length,
        uniqueTokens: uniqueCount,
        averageLength: newTokens.length > 0 ? totalLen / newTokens.length : 0,
        characterCount: inputText.length,
      });

    } catch (e: any) {
      setRegexError(`Invalid Regex: ${e.message}`);
      setTokens([]);
    }
  }, [inputText, config]);

  useEffect(() => {
    processText();
  }, [processText]);

  return (
    <div className="min-h-screen flex flex-col text-slate-800">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-20">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2 rounded-lg text-white">
              <Code2 className="w-5 h-5" />
            </div>
            <div>
                <h1 className="text-xl font-bold tracking-tight text-slate-900">TokenCraft</h1>
                <p className="text-xs text-slate-500">Visual Tokenizer Builder</p>
            </div>
          </div>
          <div className="flex items-center gap-4">
            <a 
              href="#" 
              onClick={(e) => { e.preventDefault(); alert("This is a demo. In a real app, you could save your tokenizer config URL."); }}
              className="text-slate-500 hover:text-indigo-600 transition-colors"
              title="Share Configuration"
            >
                <Share2 className="w-5 h-5" />
            </a>
            <a 
              href="https://ai.google.dev" 
              target="_blank" 
              rel="noreferrer" 
              className="text-slate-500 hover:text-indigo-600 transition-colors"
              title="Powered by Gemini"
            >
                <HelpCircle className="w-5 h-5" />
            </a>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 h-full">

          {/* Left Column: Configuration (4 cols) */}
          <div className="lg:col-span-4 flex flex-col gap-6">
            <TokenizerBuilder config={config} onConfigChange={setConfig} />

            {/* Input Text Area - Placed here for flow: Config -> Input -> Output */}
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 flex flex-col gap-3 flex-1">
                <div className="flex items-center gap-2 border-b border-slate-100 pb-3">
                    <Terminal className="w-5 h-5 text-indigo-600" />
                    <h2 className="text-lg font-semibold text-slate-800">Test Input</h2>
                </div>
                <textarea
                    className="w-full h-full min-h-[200px] p-3 text-sm font-mono border border-slate-300 rounded-md focus:outline-none focus:ring-2 focus:ring-indigo-500 resize-none bg-slate-50 text-slate-800"
                    value={inputText}
                    onChange={(e) => setInputText(e.target.value)}
                    placeholder="Enter text to tokenize..."
                />
            </div>
          </div>

          {/* Right Column: Visualization (8 cols) */}
          <div className="lg:col-span-8 flex flex-col gap-6">
            {regexError ? (
                <div className="bg-red-50 border border-red-200 text-red-700 p-4 rounded-xl flex items-center justify-center h-32">
                    <p className="font-medium">{regexError}</p>
                </div>
            ) : (
                <TokenDisplay text={inputText} tokens={tokens} stats={stats} />
            )}
          </div>
        </div>
      </main>

      <footer className="bg-white border-t border-slate-200 py-6 mt-auto">
        <div className="max-w-7xl mx-auto px-4 text-center text-slate-400 text-sm">
            <p>Built with React & Gemini. TokenCraft helps you understand how LLMs see text.</p>
        </div>
      </footer>
    </div>
  );
};

export default App;

export interface Token {
  id: number;
  value: string;
  type?: string;
  index: number; // Position in original string
  isSpecial?: boolean;
}

export interface TokenizerConfig {
  name: string;
  regex: string;
  flags: string;
  description?: string;
}

export interface TokenStats {
  totalTokens: number;
  uniqueTokens: number;
  averageLength: number;
  characterCount: number;
}

export interface TokenizerModel {
    vocab: Record<string, number>; // Token string -> ID
    merges: [string, string][];    // Ordered list of merges
    specialTokens: string[];
    regexConfig: TokenizerConfig;
}

export interface TrainingConfig {
    vocabSize: number;
    specialTokens: string[]; // e.g., ["<UNK>", "<PAD>", "<EOS>"]
}

import { TokenizerConfig, TokenizerModel, Token } from "../types";

export class BPETokenizer {
  vocab: Map<string, number>;
  reverseVocab: Map<number, string>;
  merges: Map<string, string>; // "part1,part2" -> "part1part2"
  specialTokens: Set<string>;
  regex: RegExp;
  config: TokenizerConfig;

  constructor(model?: TokenizerModel) {
    this.vocab = new Map();
    this.reverseVocab = new Map();
    this.merges = new Map();
    this.specialTokens = new Set();
    this.config = { name: "Default", regex: "\\s+", flags: "g" };
    this.regex = new RegExp(this.config.regex, this.config.flags);

    if (model) {
      this.loadModel(model);
    }
  }

  loadModel(model: TokenizerModel) {
    this.vocab = new Map(Object.entries(model.vocab));
    this.reverseVocab = new Map(Object.entries(model.vocab).map(([k, v]) => [v, k]));
    this.config = model.regexConfig;
    this.regex = new RegExp(model.regexConfig.regex, model.regexConfig.flags);
    this.specialTokens = new Set(model.specialTokens);

    // Reconstruct merges map if needed (simplified for inference)
    model.merges.forEach(([a, b]) => {
      this.merges.set(`${a},${b}`, a + b);
    });
  }

  // Pre-tokenize: Split text using the user's regex
  preTokenize(text: string): string[] {
    const matches = text.match(this.regex);
    return matches ? Array.from(matches) : [];
  }

  train(corpus: string, vocabSize: number, regexConfig: TokenizerConfig, specialTokens: string[]) {
    this.config = regexConfig;
    this.regex = new RegExp(regexConfig.regex, regexConfig.flags);
    this.specialTokens = new Set(specialTokens);
    this.vocab.clear();
    this.reverseVocab.clear();
    this.merges.clear();

    // 1. Initialize Vocab with Special Tokens
    let nextId = 0;
    specialTokens.forEach(token => {
      this.vocab.set(token, nextId);
      this.reverseVocab.set(nextId, token);
      nextId++;
    });

    // 2. Pre-tokenize corpus to get initial word list
    const words = this.preTokenize(corpus);

    // 3. Initialize working words as arrays of characters
    // "Hello" -> ["H", "e", "l", "l", "o"]
    let splits: string[][] = words.map(w => w.split(''));

    // 4. Add all initial characters to vocab
    const charSet = new Set<string>();
    splits.forEach(word => word.forEach(char => charSet.add(char)));
    Array.from(charSet).sort().forEach(char => {
      if (!this.vocab.has(char)) {
        this.vocab.set(char, nextId);
        this.reverseVocab.set(nextId, char);
        nextId++;
      }
    });

    // 5. BPE Loop
    while (this.vocab.size < vocabSize) {
      const pairs = new Map<string, number>();

      // Count pairs
      for (const word of splits) {
        for (let i = 0; i < word.length - 1; i++) {
          const pair = `${word[i]},${word[i+1]}`;
          pairs.set(pair, (pairs.get(pair) || 0) + 1);
        }
      }

      if (pairs.size === 0) break;

      // Find most frequent pair
      let bestPair = "";
      let maxCount = -1;
      for (const [pair, count] of pairs.entries()) {
        if (count > maxCount) {
          maxCount = count;
          bestPair = pair;
        }
      }

      if (maxCount < 1) break;

      // Merge
      const [part1, part2] = bestPair.split(',');
      const newToken = part1 + part2;

      this.vocab.set(newToken, nextId);
      this.reverseVocab.set(nextId, newToken);
      this.merges.set(bestPair, newToken);
      nextId++;

      // Apply merge to splits
      for (let i = 0; i < splits.length; i++) {
        const word = splits[i];
        const newWord: string[] = [];
        let j = 0;
        while (j < word.length) {
          if (j < word.length - 1 && word[j] === part1 && word[j+1] === part2) {
            newWord.push(newToken);
            j += 2;
          } else {
            newWord.push(word[j]);
            j++;
          }
        }
        splits[i] = newWord;
      }
    }

    console.log(`Training complete. Vocab size: ${this.vocab.size}`);
  }

  encode(text: string): Token[] {
    const words = this.preTokenize(text);
    const tokens: Token[] = [];
    let currentIndex = 0;

    // Helper to find original index (simple approximation for demo)
    const findIndex = (str: string, startPos: number) => {
        return text.indexOf(str, startPos);
    };

    for (const word of words) {
        let wordParts = word.split('');

        // Apply merges repeatedly until no more changes
        // This is a naive application for the demo; optimized BPE uses a priority queue or the merge list order
        // Since we didn't store merge order in a simple list for this class efficiently, we iterate.
        // For a robust implementation, we should iterate through the learned merges in order.

        // However, since we have the final vocab, a greedy approach works "okay" for demo, 
        // but strictly we should replay merges.
        // Let's do a simple loop that tries to merge adjacent pairs if they exist in vocab.
        // NOTE: This is simplified. Correct BPE requires applying merges in the order they were learned.

        // To be correct without storing the ordered merge list in memory for this function:
        // We will just assume the 'splits' logic from training or a greedy longest-match from vocab?
        // Actually, let's just do a greedy merge loop which is common for "WordPiece" style, 
        // or re-implement strict BPE if we had the ordered list.

        // For this demo, let's keep it simple: Re-scan for known tokens.

        let changed = true;
        while(changed) {
            changed = false;
            const newParts: string[] = [];
            let i = 0;
            while(i < wordParts.length) {
                if (i < wordParts.length - 1) {
                    const pair = wordParts[i] + wordParts[i+1];
                    if (this.vocab.has(pair)) {
                         // This is slightly incorrect for strict BPE (which cares about merge priority), 
                         // but visually effective for a custom tokenizer demo to show agglomeration.
                         // To do it strictly right, we'd need to store the 'rank' of every token.
                         newParts.push(pair);
                         i += 2;
                         changed = true;
                         continue;
                    }
                }
                newParts.push(wordParts[i]);
                i++;
            }
            wordParts = newParts;
        }

        // Map to IDs
        const wordStartIndex = findIndex(word, currentIndex);
        currentIndex = wordStartIndex + word.length; // Advance

        // We don't have exact char indices for sub-parts easily without tracking, 
        // so we'll just approximate index for the visualizer
        let localOffset = 0;

        for (const part of wordParts) {
            const id = this.vocab.get(part);
            const isUnknown = id === undefined;
            // Fallback for unknown chars (shouldn't happen if trained on this text, but possible on new text)
            const finalId = id !== undefined ? id : (this.vocab.get("<UNK>") ?? -1);

            tokens.push({
                id: finalId,
                value: part,
                index: wordStartIndex + localOffset,
                isSpecial: this.specialTokens.has(part)
            });
            localOffset += part.length;
        }
    }
    return tokens;
  }

  decode(ids: number[]): string {
    return ids.map(id => this.reverseVocab.get(id) || "").join("");
  }
}

import React, { useState } from 'react';
import { BPETokenizer } from '../utils/bpeTokenizer';
import { TokenizerConfig } from '../types';
import { Play, RotateCcw, Save, Database, Plus, X } from 'lucide-react';
import TokenizerBuilder from './TokenizerBuilder';

interface TrainerProps {
    tokenizer: BPETokenizer;
    onModelTrained: (model: BPETokenizer) => void;
    initialConfig: TokenizerConfig;
}

const DEFAULT_CORPUS = `The quick brown fox jumps over the lazy dog.
Machine learning is fascinating.
Tokenization is the first step in NLP.
Byte Pair Encoding (BPE) is a popular algorithm.
This is a test corpus to see how vocabulary is built.
Foxes are clever animals.
Dogs are loyal companions.`;

const Trainer: React.FC<TrainerProps> = ({ tokenizer, onModelTrained, initialConfig }) => {
    const [regexConfig, setRegexConfig] = useState<TokenizerConfig>(initialConfig);
    const [corpus, setCorpus] = useState(DEFAULT_CORPUS);
    const [vocabSize, setVocabSize] = useState(200);
    const [specialTokens, setSpecialTokens] = useState<string[]>(["<UNK>", "<PAD>", "<EOS>"]);
    const [newSpecialToken, setNewSpecialToken] = useState("");
    const [isTraining, setIsTraining] = useState(false);
    const [trainStats, setTrainStats] = useState<{vocabSize: number} | null>(null);

    const handleAddSpecialToken = () => {
        if (newSpecialToken && !specialTokens.includes(newSpecialToken)) {
            setSpecialTokens([...specialTokens, newSpecialToken]);
            setNewSpecialToken("");
        }
    };

    const handleRemoveSpecialToken = (token: string) => {
        setSpecialTokens(specialTokens.filter(t => t !== token));
    };

    const runTraining = async () => {
        setIsTraining(true);
        // Small timeout to allow UI to update
        setTimeout(() => {
            try {
                const newTokenizer = new BPETokenizer();
                newTokenizer.train(corpus, vocabSize, regexConfig, specialTokens);
                onModelTrained(newTokenizer);
                setTrainStats({ vocabSize: newTokenizer.vocab.size });
            } catch (e) {
                console.error(e);
                alert("Training failed. Check your regex or corpus.");
            } finally {
                setIsTraining(false);
            }
        }, 100);
    };

    return (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 h-full">
            {/* Left Col: Configuration */}
            <div className="flex flex-col gap-6">
                <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
                    <h3 className="text-lg font-semibold text-slate-800 mb-4 flex items-center gap-2">
                        <Database className="w-5 h-5 text-indigo-600" />
                        1. Pre-Tokenization
                    </h3>
                    <p className="text-sm text-slate-500 mb-4">
                        Before learning tokens, we must split the raw text into words or chunks using Regex.
                    </p>
                    <div className="border border-slate-100 rounded-lg p-2 bg-slate-50">
                        <TokenizerBuilder config={regexConfig} onConfigChange={setRegexConfig} />
                    </div>
                </div>

                <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 flex-1">
                    <h3 className="text-lg font-semibold text-slate-800 mb-4">3. Training Corpus</h3>
                    <textarea 
                        className="w-full h-48 p-3 text-sm font-mono border border-slate-300 rounded-md focus:outline-none focus:ring-2 focus:ring-indigo-500 bg-slate-50 resize-none"
                        value={corpus}
                        onChange={(e) => setCorpus(e.target.value)}
                        placeholder="Paste text here to train your tokenizer..."
                    />
                    <div className="text-xs text-slate-400 mt-2 text-right">
                        {corpus.length} characters
                    </div>
                </div>
            </div>

            {/* Right Col: Parameters & Actions */}
            <div className="flex flex-col gap-6">
                <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
                    <h3 className="text-lg font-semibold text-slate-800 mb-4">2. Vocabulary Settings</h3>

                    <div className="mb-6">
                        <label className="block text-sm font-medium text-slate-700 mb-1">Target Vocabulary Size</label>
                        <input 
                            type="number" 
                            min="10" 
                            max="5000"
                            value={vocabSize}
                            onChange={(e) => setVocabSize(parseInt(e.target.value))}
                            className="w-full px-3 py-2 border border-slate-300 rounded-md focus:outline-none focus:ring-2 focus:ring-indigo-500"
                        />
                        <p className="text-xs text-slate-500 mt-1">
                            The algorithm will merge characters until this limit is reached.
                        </p>
                    </div>

                    <div className="mb-6">
                        <label className="block text-sm font-medium text-slate-700 mb-2">Special Tokens</label>
                        <div className="flex flex-wrap gap-2 mb-3">
                            {specialTokens.map(token => (
                                <span key={token} className="bg-indigo-50 text-indigo-700 px-2 py-1 rounded-md text-xs font-mono border border-indigo-100 flex items-center gap-1">
                                    {token}
                                    <button onClick={() => handleRemoveSpecialToken(token)} className="hover:text-indigo-900"><X className="w-3 h-3"/></button>
                                </span>
                            ))}
                        </div>
                        <div className="flex gap-2">
                            <input 
                                type="text" 
                                value={newSpecialToken}
                                onChange={(e) => setNewSpecialToken(e.target.value)}
                                onKeyDown={(e) => e.key === 'Enter' && handleAddSpecialToken()}
                                placeholder="Add token (e.g. <SEP>)"
                                className="flex-1 px-3 py-2 text-sm border border-slate-300 rounded-md focus:outline-none focus:ring-2 focus:ring-indigo-500"
                            />
                            <button 
                                onClick={handleAddSpecialToken}
                                className="px-3 py-2 bg-slate-100 text-slate-600 rounded-md hover:bg-slate-200"
                            >
                                <Plus className="w-4 h-4" />
                            </button>
                        </div>
                    </div>
                </div>

                <div className="bg-gradient-to-br from-indigo-600 to-violet-700 rounded-xl shadow-lg p-6 text-white flex flex-col items-center justify-center gap-4 flex-1 min-h-[200px]">
                    <div className="text-center">
                        <h2 className="text-2xl font-bold mb-2">Ready to Train?</h2>
                        <p className="text-indigo-100 text-sm max-w-xs mx-auto">
                            The tokenizer will learn from your corpus and build a vocabulary of {vocabSize} tokens.
                        </p>
                    </div>

                    <button 
                        onClick={runTraining}
                        disabled={isTraining}
                        className={`px-8 py-3 bg-white text-indigo-700 rounded-full font-bold shadow-lg hover:shadow-xl transform transition-all active:scale-95 flex items-center gap-2 ${isTraining ? 'opacity-70 cursor-wait' : 'hover:-translate-y-1'}`}
                    >
                        {isTraining ? <RotateCcw className="w-5 h-5 animate-spin"/> : <Play className="w-5 h-5 fill-current"/>}
                        {isTraining ? 'Training...' : 'Train Tokenizer'}
                    </button>

                    {trainStats && (
                        <div className="mt-4 bg-white/20 px-4 py-2 rounded-lg backdrop-blur-sm text-sm">
                            Training Complete! Vocab Size: {trainStats.vocabSize}
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

export default Trainer;

import React, { useState, useEffect } from 'react';
import { BPETokenizer } from '../utils/bpeTokenizer';
import { Token } from '../types';
import { ArrowRight, ArrowDown, Code, Type } from 'lucide-react';

interface PlaygroundProps {
    tokenizer: BPETokenizer;
}

const Playground: React.FC<PlaygroundProps> = ({ tokenizer }) => {
    const [inputText, setInputText] = useState("Hello world! This is a test.");
    const [encodedTokens, setEncodedTokens] = useState<Token[]>([]);

    const [inputIds, setInputIds] = useState("");
    const [decodedText, setDecodedText] = useState("");

    // Encoding Effect
    useEffect(() => {
        if (!tokenizer) return;
        try {
            const tokens = tokenizer.encode(inputText);
            setEncodedTokens(tokens);
            // Also auto-populate the decoder input with these IDs for convenience
            setInputIds(tokens.map(t => t.id).join(", "));
        } catch (e) {
            console.error(e);
        }
    }, [inputText, tokenizer]);

    // Decoding Effect
    useEffect(() => {
        if (!tokenizer) return;
        try {
            const ids = inputIds.split(',').map(s => parseInt(s.trim())).filter(n => !isNaN(n));
            const text = tokenizer.decode(ids);
            setDecodedText(text);
        } catch (e) {
            console.error(e);
        }
    }, [inputIds, tokenizer]);

    // Colors for visualization
    const getColor = (id: number) => {
        const colors = [
            'bg-blue-100 text-blue-900 border-blue-200',
            'bg-emerald-100 text-emerald-900 border-emerald-200',
            'bg-amber-100 text-amber-900 border-amber-200',
            'bg-rose-100 text-rose-900 border-rose-200',
            'bg-violet-100 text-violet-900 border-violet-200',
            'bg-cyan-100 text-cyan-900 border-cyan-200',
        ];
        return colors[id % colors.length];
    };

    return (
        <div className="flex flex-col gap-8 h-full">

            {/* Encoder Section */}
            <div className="grid grid-cols-1 md:grid-cols-12 gap-6 bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                <div className="md:col-span-12 bg-slate-50 border-b border-slate-200 px-6 py-3 flex items-center gap-2">
                    <Code className="w-5 h-5 text-indigo-600" />
