import React, { useState, useEffect, useCallback } from 'react';
import { Code2, Share2, HelpCircle, Play, RotateCcw, Database, Settings2, Plus, X } from 'lucide-react';
import TokenizerBuilder from './components/TokenizerBuilder';
import TokenDisplay from './components/TokenDisplay';
import { TokenizerConfig, Token, TokenStats } from './types';
import { PRESET_TOKENIZERS } from './constants';
import { BPETokenizer } from './utils/bpeTokenizer';

const DEFAULT_CORPUS = `The quick brown fox jumps over the lazy dog.
Machine learning is fascinating.
Tokenization is the first step in NLP.
Byte Pair Encoding (BPE) is a popular algorithm.
Foxes are clever animals.
Dogs are loyal companions.`;

const DEFAULT_INPUT = "The quick brown fox jumps over the lazy dog.";

const App: React.FC = () => {
  // --- State ---
  // Configuration
  const [regexConfig, setRegexConfig] = useState<TokenizerConfig>(PRESET_TOKENIZERS[0]);
  const [corpus, setCorpus] = useState(DEFAULT_CORPUS);
  const [vocabSize, setVocabSize] = useState(300);
  const [specialTokens, setSpecialTokens] = useState<string[]>(["<UNK>", "<PAD>"]);
  const [newSpecialToken, setNewSpecialToken] = useState("");

  // Model & Processing
  const [tokenizer, setTokenizer] = useState<BPETokenizer>(new BPETokenizer());
  const [isTraining, setIsTraining] = useState(false);
  const [trainStatus, setTrainStatus] = useState<string>("");

  // Live Testing
  const [inputText, setInputText] = useState(DEFAULT_INPUT);
  const [tokens, setTokens] = useState<Token[]>([]);
  const [stats, setStats] = useState<TokenStats>({
    totalTokens: 0,
    uniqueTokens: 0,
    averageLength: 0,
    characterCount: 0,
  });
  const [decodedPreview, setDecodedPreview] = useState("");

  // --- Handlers ---

  const handleTrain = useCallback(async () => {
    setIsTraining(true);
    setTrainStatus("Training...");

    // Allow UI to update before blocking with heavy calculation
    setTimeout(() => {
        try {
            const newTokenizer = new BPETokenizer();
            // Train the model
            newTokenizer.train(corpus, vocabSize, regexConfig, specialTokens);
            setTokenizer(newTokenizer);
            setTrainStatus(`Done! Vocab: ${newTokenizer.vocab.size}`);

            // Re-process current input with new model
            const newTokens = newTokenizer.encode(inputText);
            updateStats(newTokens, inputText, newTokenizer);
        } catch (e) {
            console.error(e);
            setTrainStatus("Error during training");
        } finally {
            setIsTraining(false);
            // Clear status after a few seconds
            setTimeout(() => setTrainStatus(""), 3000);
        }
    }, 100);
  }, [corpus, vocabSize, regexConfig, specialTokens, inputText]);

  // Initial Training on Mount
  useEffect(() => {
    handleTrain();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []); // Run once

  // Live Encoding when input changes
  useEffect(() => {
    if (tokenizer) {
        const newTokens = tokenizer.encode(inputText);
        updateStats(newTokens, inputText, tokenizer);
    }
  }, [inputText, tokenizer]);

  const updateStats = (currentTokens: Token[], text: string, model: BPETokenizer) => {
    setTokens(currentTokens);

    // Calculate Stats
    const uniqueCount = new Set(currentTokens.map(t => t.value)).size;
    const totalLen = currentTokens.reduce((acc, t) => acc + t.value.length, 0);

    setStats({
      totalTokens: currentTokens.length,
      uniqueTokens: uniqueCount,
      averageLength: currentTokens.length > 0 ? totalLen / currentTokens.length : 0,
      characterCount: text.length,
    });

    // Verify Decoding
    const ids = currentTokens.map(t => t.id);
    setDecodedPreview(model.decode(ids));
  };

  const handleAddSpecialToken = () => {
    if (newSpecialToken && !specialTokens.includes(newSpecialToken)) {
        setSpecialTokens([...specialTokens, newSpecialToken]);
        setNewSpecialToken("");
    }
  };

  const handleRemoveSpecialToken = (token: string) => {
    setSpecialTokens(specialTokens.filter(t => t !== token));
  };

  return (
    <div className="min-h-screen flex flex-col text-slate-800 bg-slate-50 font-sans">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-30 shadow-sm">
        <div className="max-w-[1600px] mx-auto px-4 sm:px-6 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2 rounded-lg text-white shadow-md">
              <Code2 className="w-5 h-5" />
            </div>
            <div>
                <h1 className="text-xl font-bold tracking-tight text-slate-900 leading-tight">TokenCraft</h1>
                <p className="text-[10px] text-slate-500 font-medium uppercase tracking-wide">Custom Tokenizer Builder</p>
            </div>
          </div>
          <div className="flex items-center gap-3">
            <div className="hidden md:flex items-center gap-2 px-3 py-1 bg-indigo-50 text-indigo-700 rounded-full text-xs font-medium border border-indigo-100">
                <span className={`w-2 h-2 rounded-full ${isTraining ? 'bg-amber-400 animate-pulse' : 'bg-emerald-400'}`}></span>
                {isTraining ? 'Training Model...' : trainStatus || 'Model Ready'}
            </div>
            <a href="https://ai.google.dev" target="_blank" rel="noreferrer" className="text-slate-400 hover:text-indigo-600 transition-colors">
                <HelpCircle className="w-5 h-5" />
            </a>
          </div>
        </div>
      </header>

      {/* Main Content - Grid Layout */}
      <main className="flex-1 max-w-[1600px] w-full mx-auto p-4 sm:p-6 lg:p-8">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 h-full min-h-[calc(100vh-8rem)]">

          {/* --- LEFT COLUMN: CONFIGURATION (4/12) --- */}
          <div className="lg:col-span-4 xl:col-span-3 flex flex-col gap-6 h-full overflow-y-auto pr-1">

            {/* 1. Regex Config */}
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                <div className="px-4 py-3 border-b border-slate-100 bg-slate-50 flex items-center gap-2">
                    <Settings2 className="w-4 h-4 text-indigo-600" />
                    <h2 className="font-semibold text-sm text-slate-800">Pre-tokenization</h2>
                </div>
                <div className="p-4">
                    <TokenizerBuilder config={regexConfig} onConfigChange={setRegexConfig} />
                </div>
            </div>

            {/* 2. Training Data & Vocab */}
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 flex-1 flex flex-col overflow-hidden">
                <div className="px-4 py-3 border-b border-slate-100 bg-slate-50 flex items-center justify-between">
                    <div className="flex items-center gap-2">
                        <Database className="w-4 h-4 text-indigo-600" />
                        <h2 className="font-semibold text-sm text-slate-800">Training Corpus</h2>
                    </div>
                    <span className="text-xs text-slate-400">{corpus.length} chars</span>
                </div>

                <div className="p-4 flex-1 flex flex-col gap-4">
                    <textarea 
                        className="w-full flex-1 min-h-[120px] p-3 text-xs font-mono border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 bg-slate-50 resize-y text-slate-600 leading-relaxed"
                        value={corpus}
                        onChange={(e) => setCorpus(e.target.value)}
                        placeholder="Paste text here to train the tokenizer..."
                    />

                    <div className="grid grid-cols-2 gap-3">
                        <div>
                            <label className="block text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1">Vocab Size</label>
                            <input 
                                type="number" 
                                value={vocabSize}
                                onChange={(e) => setVocabSize(parseInt(e.target.value))}
                                className="w-full px-2 py-1.5 text-sm border border-slate-200 rounded focus:outline-none focus:ring-2 focus:ring-indigo-500"
                            />
                        </div>
                        <div className="flex items-end">
                             <button 
                                onClick={handleTrain}
                                disabled={isTraining}
                                className="w-full py-2 bg-indigo-600 text-white rounded-lg text-sm font-medium hover:bg-indigo-700 disabled:opacity-50 flex items-center justify-center gap-2 shadow-sm transition-all active:scale-95"
                            >
                                {isTraining ? <RotateCcw className="w-4 h-4 animate-spin"/> : <Play className="w-4 h-4 fill-current"/>}
                                {isTraining ? 'Wait' : 'Train'}
                            </button>
                        </div>
                    </div>

                    <div className="pt-2 border-t border-slate-100">
                        <label className="block text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-2">Special Tokens</label>
                        <div className="flex flex-wrap gap-1.5 mb-2">
                            {specialTokens.map(token => (
                                <span key={token} className="bg-slate-100 text-slate-600 px-2 py-0.5 rounded text-[10px] font-mono border border-slate-200 flex items-center gap-1 group">
                                    {token}
                                    <button onClick={() => handleRemoveSpecialToken(token)} className="text-slate-400 group-hover:text-red-500"><X className="w-3 h-3"/></button>
                                </span>
                            ))}
                        </div>
                        <div className="flex gap-1">
                            <input 
                                type="text" 
                                value={newSpecialToken}
                                onChange={(e) => setNewSpecialToken(e.target.value)}
                                onKeyDown={(e) => e.key === 'Enter' && handleAddSpecialToken()}
                                placeholder="Add (e.g. <SEP>)"
                                className="flex-1 px-2 py-1 text-xs border border-slate-200 rounded focus:outline-none focus:ring-2 focus:ring-indigo-500"
                            />
                            <button onClick={handleAddSpecialToken} className="p-1 bg-slate-100 text-slate-500 rounded hover:bg-slate-200"><Plus className="w-4 h-4"/></button>
                        </div>
                    </div>
                </div>
            </div>
          </div>

          {/* --- RIGHT COLUMN: PLAYGROUND (8/12) --- */}
          <div className="lg:col-span-8 xl:col-span-9 flex flex-col gap-6 h-full">

            {/* Input Area */}
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex-shrink-0">
                <div className="px-4 py-3 border-b border-slate-100 bg-slate-50 flex items-center gap-2">
                    <Code2 className="w-4 h-4 text-indigo-600" />
                    <h2 className="font-semibold text-sm text-slate-800">Test Input</h2>
                </div>
                <div className="p-0">
                    <textarea 
                        className="w-full h-32 p-4 text-lg border-0 focus:ring-0 resize-none text-slate-800 placeholder-slate-300 font-normal leading-relaxed"
                        value={inputText}
                        onChange={(e) => setInputText(e.target.value)}
                        placeholder="Type something to tokenize immediately..."
                    />
                </div>
            </div>

            {/* Visualization */}
            <div className="flex-1 min-h-[400px]">
                <TokenDisplay tokens={tokens} stats={stats} decodedText={decodedPreview} />
            </div>

          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback } from 'react';
import { Code2, RefreshCw, Save, ArrowRight, Settings2, Database, ALargeSmall } from 'lucide-react';
import TokenizerBuilder from './components/TokenizerBuilder';
import TokenDisplay from './components/TokenDisplay';
import { TokenizerConfig, Token, TokenStats } from './types';
import { PRESET_TOKENIZERS } from './constants';
import { BPETokenizer } from './utils/bpeTokenizer';

const DEFAULT_CORPUS = `The quick brown fox jumps over the lazy dog.
Machine learning is fascinating.
Tokenization is the first step in NLP.
Byte Pair Encoding (BPE) is a popular algorithm.
Foxes are clever animals.
Dogs are loyal companions.`;

const DEFAULT_INPUT = "The quick brown fox jumps over the lazy dog.";

const App: React.FC = () => {
  // --- Configuration State ---
  const [regexConfig, setRegexConfig] = useState<TokenizerConfig>(PRESET_TOKENIZERS[0]);
  const [corpus, setCorpus] = useState(DEFAULT_CORPUS);
  const [vocabSize, setVocabSize] = useState(300);
  const [specialTokensString, setSpecialTokensString] = useState("<UNK>, <PAD>");

  // --- Model State ---
  const [tokenizer, setTokenizer] = useState<BPETokenizer>(new BPETokenizer());
  const [isTraining, setIsTraining] = useState(false);

  // --- Live Test State ---
  const [inputText, setInputText] = useState(DEFAULT_INPUT);
  const [tokens, setTokens] = useState<Token[]>([]);
  const [decodedText, setDecodedText] = useState("");
  const [stats, setStats] = useState<TokenStats>({
    totalTokens: 0,
    uniqueTokens: 0,
    averageLength: 0,
    characterCount: 0,
  });

  // --- Actions ---

  const handleTrain = useCallback(() => {
    setIsTraining(true);
    // Use setTimeout to allow UI to render the loading state
    setTimeout(() => {
        try {
            // Parse special tokens
            const specialTokens = specialTokensString
                .split(',')
                .map(s => s.trim())
                .filter(s => s.length > 0);

            const newTokenizer = new BPETokenizer();
            newTokenizer.train(corpus, vocabSize, regexConfig, specialTokens);
            setTokenizer(newTokenizer);

            // Auto-update the tokens for current input
            const newTokens = newTokenizer.encode(inputText);
            updateVisuals(newTokens, inputText, newTokenizer);
        } catch (e) {
            console.error("Training Error", e);
        } finally {
            setIsTraining(false);
        }
    }, 50);
  }, [corpus, vocabSize, regexConfig, specialTokensString, inputText]);

  // Initial Train
  useEffect(() => {
    handleTrain();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Update visuals helper
  const updateVisuals = (currentTokens: Token[], text: string, model: BPETokenizer) => {
    setTokens(currentTokens);

    // Calculate stats
    const uniqueCount = new Set(currentTokens.map(t => t.value)).size;
    const totalLen = currentTokens.reduce((acc, t) => acc + t.value.length, 0);
    setStats({
      totalTokens: currentTokens.length,
      uniqueTokens: uniqueCount,
      averageLength: currentTokens.length > 0 ? totalLen / currentTokens.length : 0,
      characterCount: text.length,
    });

    // Check decoding
    const ids = currentTokens.map(t => t.id);
    setDecodedText(model.decode(ids));
  };

  // Live input change
  const handleInputChange = (text: string) => {
    setInputText(text);
    if (tokenizer) {
        const newTokens = tokenizer.encode(text);
        updateVisuals(newTokens, text, tokenizer);
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50 text-slate-800 font-sans">
      {/* Simple Header */}
      <header className="bg-white border-b border-slate-200 h-14 flex items-center px-6 sticky top-0 z-30">
        <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-1.5 rounded text-white">
              <Code2 className="w-4 h-4" />
            </div>
            <h1 className="font-bold text-slate-900 tracking-tight">TokenCraft</h1>
        </div>
        <div className="ml-auto flex items-center gap-4 text-xs text-slate-500">
            <span>Vocab Size: <strong>{tokenizer.vocab.size}</strong></span>
            <div className="h-4 w-px bg-slate-200"></div>
