import { encodingForModel } from "js-tiktoken";
import { Token } from "../types";

// Cache the encoder to avoid reloading WASM/mappings unnecessarily
let enc: ReturnType<typeof encodingForModel> | null = null;

export const getGPTTokens = (text: string): Token[] => {
  if (!enc) {
    try {
      enc = encodingForModel("gpt-4o"); // Uses standard cl100k_base
    } catch (e) {
      console.error("Failed to load tokenizer", e);
      return [];
    }
  }

  const encoded = enc.encode(text);
  const tokens: Token[] = [];

  // We need to decode one by one to get the string representation for visualization
  // This is slow for massive text but fine for a UI playground
  let currentIndex = 0;

  // To get byte-accurate offsets, we track the text. 
  // However, tiktoken decoding is byte-level.
  // For visualization simplicity, we will just map IDs back to text fragments.

  for (const id of encoded) {
    const fragment = new TextDecoder().decode(enc.decode([id]));
    tokens.push({
      id: id,
      value: fragment,
      index: currentIndex, 
      type: "GPT-4"
    });
    currentIndex += fragment.length;
  }

  return tokens;
};

export const decodeGPT = (ids: number[]): string => {
    if (!enc) enc = encodingForModel("gpt-4o");
    return new TextDecoder().decode(enc.decode(ids));
};

