import { encodingForModel, getEncoding } from "js-tiktoken";
import { Token } from "../types";

// Cache the encoder to avoid reloading mappings unnecessarily
// We use 'any' for the encoder type here to avoid tight coupling with the library version in the types
let enc: any | null = null;

export const getGPTTokens = (text: string): Token[] => {
  try {
    if (!enc) {
        // Fallback to 'cl100k_base' directly if model name fails, or use gpt-4
        try {
            enc = encodingForModel("gpt-4"); 
        } catch (e) {
            console.warn("Could not load gpt-4 model, trying cl100k_base directly", e);
            try {
                enc = getEncoding("cl100k_base");
            } catch (e2) {
                console.error("Failed to load GPT tokenizer completely", e2);
                return [];
            }
        }
    }

    if (!enc) return [];

    const encoded = enc.encode(text);
    const tokens: Token[] = [];

    let currentIndex = 0;

    // We decode one by one for visualization purposes. 
    // Ideally we would decode the whole array and map, but js-tiktoken 
    // gives us bytes/text.
    for (const id of encoded) {
      const bytes = enc.decode([id]);
      const fragment = new TextDecoder().decode(bytes);

      tokens.push({
        id: id,
        value: fragment,
        index: currentIndex, 
        type: "GPT-4"
      });
      currentIndex += fragment.length;
    }

    return tokens;
  } catch (error) {
    console.error("Error in getGPTTokens:", error);
    // Return empty array instead of crashing
    return [];
  }
};

export const decodeGPT = (ids: number[]): string => {
    try {
        if (!enc) enc = encodingForModel("gpt-4");
        return new TextDecoder().decode(enc.decode(ids));
    } catch (e) {
        return "";
    }
};

