import { GoogleGenAI, Type } from "@google/genai";
import { TokenizerConfig } from "../types";

let ai: GoogleGenAI | null = null;

const getAI = () => {
    if (!ai) {
        // Safe access to process.env.API_KEY
        // In the polyfill it might be empty, so real app usage relies on injection or the polyfill being updated
        const key = typeof process !== 'undefined' ? process.env.API_KEY : '';
        ai = new GoogleGenAI({ apiKey: key });
    }
    return ai;
};

export const generateTokenizerWithGemini = async (
  prompt: string
): Promise<TokenizerConfig | null> => {
  try {
    const client = getAI();
    const response = await client.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Create a JavaScript Regular Expression (Regex) that functions as a tokenizer based on this user description: "${prompt}".

      The regex should match the *tokens* themselves, not the delimiters. 
      For example, if the user wants to split by space, the regex should match non-space characters (\\S+).
      If the user wants to keep emails together, the regex should explicitly match email patterns OR other words.

      Return the result as a JSON object.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            regex: {
              type: Type.STRING,
              description: "The JavaScript regex pattern string (without slashes). Escape backslashes correctly.",
            },
            flags: {
              type: Type.STRING,
              description: "Regex flags (e.g., 'g', 'gi'). Usually 'g' is required.",
            },
            description: {
              type: Type.STRING,
              description: "A short explanation of how this regex works.",
            },
            name: {
              type: Type.STRING,
              description: "A short, creative name for this tokenizer strategy.",
            },
          },
          required: ["regex", "flags", "description", "name"],
        },
      },
    });

    if (response.text) {
      return JSON.parse(response.text) as TokenizerConfig;
    }
    return null;
  } catch (error) {
    console.error("Error generating tokenizer:", error);
    throw error;
  }
};

export const explainTokenizer = async (regex: string): Promise<string> => {
    try {
        const client = getAI();
        const response = await client.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: `Explain what this Regular Expression does in the context of text tokenization in one simple sentence: /${regex}/`,
        });
        return response.text || "No explanation available.";
    } catch (e) {
        return "Could not generate explanation.";
    }
}

import { Token } from "../types";

// Dynamic import type wrapper would be ideal but for simplicity we use any for the module
let tiktokenModule: any = null;
let enc: any = null;

export const getGPTTokens = async (text: string): Promise<Token[]> => {
  try {
    // Dynamically import js-tiktoken to avoid top-level load errors
    if (!tiktokenModule) {
        try {
            // @ts-ignore - dynamic import from importmap
            tiktokenModule = await import("js-tiktoken");
        } catch (e) {
            console.error("Failed to load js-tiktoken module", e);
            return [];
        }
    }

    if (!enc && tiktokenModule) {
        try {
            enc = tiktokenModule.encodingForModel("gpt-4"); 
        } catch (e) {
            console.warn("Could not load gpt-4 model, trying cl100k_base directly", e);
            try {
                enc = tiktokenModule.getEncoding("cl100k_base");
            } catch (e2) {
                console.error("Failed to load GPT tokenizer completely", e2);
                return [];
            }
        }
    }

    if (!enc) return [];

    const encoded = enc.encode(text);
    const tokens: Token[] = [];

    let currentIndex = 0;

    // We decode one by one for visualization purposes.
    for (const id of encoded) {
      const bytes = enc.decode([id]);
      const fragment = new TextDecoder().decode(bytes);

      tokens.push({
        id: id,
        value: fragment,
        index: currentIndex, 
        type: "GPT-4"
      });
      currentIndex += fragment.length;
    }

    return tokens;
  } catch (error) {
    console.error("Error in getGPTTokens:", error);
    return [];
  }
};

